import{o as e,c as n,a as s}from"./app.a612cc0f.js";const a='{"title":"Quick Docs","description":"","frontmatter":{},"headers":[{"level":2,"title":"yarn 与 npm","slug":"yarn-与-npm"},{"level":2,"title":"yarn 安装","slug":"yarn-安装"},{"level":2,"title":"link 软连接本地组件库","slug":"link-软连接本地组件库"},{"level":2,"title":"npm esbuild 版本报错","slug":"npm-esbuild-版本报错"},{"level":2,"title":"npm 查看全局配置","slug":"npm-查看全局配置"},{"level":2,"title":"npm 设置成淘宝源","slug":"npm-设置成淘宝源"},{"level":2,"title":"npm 查看源配置","slug":"npm-查看源配置"},{"level":2,"title":"cnpm","slug":"cnpm"},{"level":2,"title":"nrm 源镜像","slug":"nrm-源镜像"},{"level":2,"title":"gulp-sass","slug":"gulp-sass"},{"level":2,"title":"node-sass","slug":"node-sass"},{"level":2,"title":"node-gyp","slug":"node-gyp"},{"level":2,"title":"SSH Key","slug":"ssh-key"},{"level":2,"title":"git 命令","slug":"git-命令"},{"level":2,"title":"刷新 dns hosts","slug":"刷新-dns-hosts"},{"level":2,"title":"最常用的镜像地址：","slug":"最常用的镜像地址："},{"level":2,"title":"Git 报错","slug":"git-报错"},{"level":3,"title":"OpenSSL SSL_read: Connection was reset, errno 10054 错误解决","slug":"openssl-ssl-read-connection-was-reset-errno-10054-错误解决"},{"level":2,"title":"svn","slug":"svn"},{"level":3,"title":"svn 图标","slug":"svn-图标"}],"relativePath":"index.md","lastUpdated":1624605805055}',r={},l=[s('<h1 id="quick-docs"><a class="header-anchor" href="#quick-docs" aria-hidden="true">#</a> Quick Docs</h1><blockquote><p>基于 VitePress 搭建的技术文档模板</p></blockquote><p>使用最新 vue3.x 开发编写技术文档, 发布常用的工具库与 UI 库</p><h2 id="yarn-与-npm"><a class="header-anchor" href="#yarn-与-npm" aria-hidden="true">#</a> yarn 与 npm</h2><p>建议使用 yarn</p><table><thead><tr><th>属性</th><th>yarn</th><th>npm</th></tr></thead><tbody><tr><td>初始化</td><td>yarn init</td><td>npm init</td></tr><tr><td>安装依赖</td><td>yarn install 或者 yarn</td><td>npm install 或者 npm i</td></tr><tr><td>新增依赖</td><td>yarn add qveui</td><td>npm install qveui --save 或者 npm i qveui</td></tr><tr><td>新增依赖</td><td>yarn add -D qveui</td><td>npm i -D qveui</td></tr><tr><td>删除依赖</td><td>yarn remove qveui</td><td>npm uninstall qveui --save 或者 npm un qveui</td></tr><tr><td>更新依赖</td><td>yarn upgrade</td><td>npm update</td></tr><tr><td>全局安装或删除</td><td>yarn global remove vue-cli</td><td>npm uninstall vue-cli -g 或者 npm -g vue-cli</td></tr><tr><td>同时下载多个</td><td>yarn add axios vue-axios</td><td>npm install --save axios vue-axios</td></tr></tbody></table><h2 id="yarn-安装"><a class="header-anchor" href="#yarn-安装" aria-hidden="true">#</a> yarn 安装</h2><p><code>npm install -g yarn</code></p><h2 id="link-软连接本地组件库"><a class="header-anchor" href="#link-软连接本地组件库" aria-hidden="true">#</a> link 软连接本地组件库</h2><p>开发过程中，两个或多个项目之间相互依赖时，可以使用 link 将一个项目链接到另一个项目。 不需要每次都发布项目<code>npm publish</code></p><p>示例名称:qvui-rc</p><p>修改 package.json &gt; name</p><ul><li>源模块项目文件夹下执行</li></ul><div class="language-sh line-numbers-mode"><pre><code># 新项目先进行初始化生成 package.json 并配置名称\n npm init\n\n# 创建软连接 link\n\nyarn link\n\n# or\n\nnpm link\n\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><ul><li>连接这个库的项目文件夹下执行</li></ul><div class="language-sh line-numbers-mode"><pre><code># 连接 qvui-rc\nyarn link qvui-rc\n# 取消连接\nyarn unlink qvui-rc\n# or\nnpm link qvui-rc\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><ul><li>项目和模块在同一个目录下，可以使用相对路径</li></ul><p>npm link ../packages</p><ul><li>解除 link</li></ul><p>解除项目和模块 link，项目目录下，npm unlink 模块名</p><p>解除模块全局 link，模块目录下，npm unlink 模块名</p><h2 id="npm-esbuild-版本报错"><a class="header-anchor" href="#npm-esbuild-版本报错" aria-hidden="true">#</a> npm esbuild 版本报错</h2><p>npm v7 以上有个 Bug,需要执行以下安装</p><p><code>node node_modules/esbuild/install.js</code></p><h2 id="npm-查看全局配置"><a class="header-anchor" href="#npm-查看全局配置" aria-hidden="true">#</a> npm 查看全局配置</h2><p><code>npm config ls</code></p><h2 id="npm-设置成淘宝源"><a class="header-anchor" href="#npm-设置成淘宝源" aria-hidden="true">#</a> npm 设置成淘宝源</h2><p><code>npm config set registry https://registry.npm.taobao.org</code></p><h2 id="npm-查看源配置"><a class="header-anchor" href="#npm-查看源配置" aria-hidden="true">#</a> npm 查看源配置</h2><p><code>npm config get registry</code></p><h2 id="cnpm"><a class="header-anchor" href="#cnpm" aria-hidden="true">#</a> cnpm</h2><p>安装国内镜像 <code>npm install cnpm -g</code></p><h2 id="nrm-源镜像"><a class="header-anchor" href="#nrm-源镜像" aria-hidden="true">#</a> nrm 源镜像</h2><ul><li><p><a href="https://blog.csdn.net/zhuzicc/article/details/101023144" target="_blank" rel="noopener noreferrer">nrm 安装路径</a></p></li><li><p><a href="https://blog.csdn.net/qq_42046421/article/details/113851930" target="_blank" rel="noopener noreferrer">nrm ERR_INVALID_ARG_TYPE 解决方法</a></p></li><li><p>安装 <code>npm install nrm -g</code></p></li><li><p>显示源 <code>nrm ls</code></p></li></ul><div class="language-bash line-numbers-mode"><pre><code>  <span class="token function">npm</span> -------- https://registry.npmjs.org/\n  <span class="token function">yarn</span> ------- https://registry.yarnpkg.com/\n  cnpm ------- http://r.cnpmjs.org/\n* taobao ----- https://registry.npm.taobao.org/\n  nj --------- https://registry.nodejitsu.com/\n  npmMirror -- https://skimdb.npmjs.com/registry/\n  edunpm ----- http://registry.enpmjs.org/\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li>切换源 <code>nrm use npm</code></li></ul><h2 id="gulp-sass"><a class="header-anchor" href="#gulp-sass" aria-hidden="true">#</a> gulp-sass</h2><p>语法都是一样的，gulp-sass 只是将 npm 换成 cnpm <code>cnpm install --save-dev gulp-sass</code></p><p><code>yarn global add node-sass</code></p><p>遇到报错请安装 <code>node-sass</code></p><h2 id="node-sass"><a class="header-anchor" href="#node-sass" aria-hidden="true">#</a> node-sass</h2><p><code>npm install --global windows-build-tools --save</code></p><p><code>npm i -g node-sass</code> 或者 <code>cnpm i -g node-sass</code></p><p>执行 <code>npm rebuild node-sass</code></p><h2 id="node-gyp"><a class="header-anchor" href="#node-gyp" aria-hidden="true">#</a> node-gyp</h2><ol><li>安装 Visual C ++构建环境：<a href="https://visualstudio.microsoft.com/thank-you-downloading-visual-studio/?sku=BuildTools" target="_blank" rel="noopener noreferrer">Visual Studio 构建工具</a></li></ol><p><code>npm config set msbuild_path “C:\\Program Files (x86)\\Microsoft Visual Studio\\2019\\Community\\MSBuild\\Current\\Bin\\MSBuild.exe”</code></p><ol start="2"><li><p>安装 <a href="https://www.python.org/downloads/" target="_blank" rel="noopener noreferrer">Python 2.7</a>（v3.x.x 不支持），安装后要配置环境变量。 成功后执行 <code>npm config set python python2.7</code></p></li><li><p>执行 <code>npm config set msvs_version 2017</code></p></li><li><p>安装 gyp 命令： <code>npm i -g node-gyp</code><code>npm install --global node-gyp@latest</code></p></li></ol><h2 id="ssh-key"><a class="header-anchor" href="#ssh-key" aria-hidden="true">#</a> SSH Key</h2><p>这里的 <a href="mailto:xxxxx@xxxxx.com">xxxxx@xxxxx.com</a> 只是生成的 sshkey 的名称，并不约束或要求具体命名为某个邮箱</p><ul><li><p>生成按照提示完成三次回车，即可生成 ssh key <code>ssh-keygen -t rsa -C xxxxx@xxxxx.com</code></p></li><li><p>通过查看 ~/.ssh/id_rsa.pub 文件内容，获取到你的 public key 内容 <code>cat ~/.ssh/id_rsa.pub</code></p></li><li><p>复制生成的内容，更新到： <a href="https://github.com/settings/keys" target="_blank" rel="noopener noreferrer">https://github.com/settings/keys</a></p></li><li><p>绑定 Key,会提示是否 continue,输入 yes 后程序会自动连接，如果要求登录，直接输入登录信息即可 <code>ssh -T git@gitee.com</code></p></li></ul><h2 id="git-命令"><a class="header-anchor" href="#git-命令" aria-hidden="true">#</a> git 命令</h2><ul><li><a href="./guide/vscode.html">建议使用 vscode git</a></li></ul><div class="language-sh line-numbers-mode"><pre><code># 克隆拉取代码\ngit clone https://github.com/appbest/qveui-vue3-admin.git\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ul><li>常用命令</li></ul><div class="language-sh line-numbers-mode"><pre><code>\n# 1.查看git配置\n  git config --global -l\n# 2.检查环境变量\n  env|grep -i proxy\n# 新建 main 分支，并转至 main 分支\ngit checkout -b main\n\n# 合并两个分支\ngit merge main\n\n# 提交\nadd commit\n\n# 将本地 main 分支的推送至远程\ngit push -u origin main\n\n# 删除分支\ngit push origin --delete main\n\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="刷新-dns-hosts"><a class="header-anchor" href="#刷新-dns-hosts" aria-hidden="true">#</a> 刷新 dns hosts</h2><p><code>ipconfig /flushdns</code></p><h2 id="最常用的镜像地址："><a class="header-anchor" href="#最常用的镜像地址：" aria-hidden="true">#</a> 最常用的镜像地址：</h2><ul><li><a href="https://github.com.cnpmjs.org" target="_blank" rel="noopener noreferrer">https://github.com.cnpmjs.org</a></li><li><a href="https://hub.fastgit.org" target="_blank" rel="noopener noreferrer">https://hub.fastgit.org</a></li></ul><h2 id="git-报错"><a class="header-anchor" href="#git-报错" aria-hidden="true">#</a> Git 报错</h2><h3 id="openssl-ssl-read-connection-was-reset-errno-10054-错误解决"><a class="header-anchor" href="#openssl-ssl-read-connection-was-reset-errno-10054-错误解决" aria-hidden="true">#</a> OpenSSL SSL_read: Connection was reset, errno 10054 错误解决</h3><p>首先，造成这个错误很有可能是网络不稳定，连接超时导致的， 如果再次尝试后依然报错，可以执行下面的命令。</p><p>打开 Git 命令页面，执行 git 命令脚本：修改设置，解除 ssl 验证</p><p>git config --global http.sslVerify &quot;false&quot;</p><h2 id="svn"><a class="header-anchor" href="#svn" aria-hidden="true">#</a> svn</h2><ul><li><a href="https://tortoisesvn.net/downloads.html" target="_blank" rel="noopener noreferrer">svn 官网下载</a></li></ul><h3 id="svn-图标"><a class="header-anchor" href="#svn-图标" aria-hidden="true">#</a> svn 图标</h3><p>Windows Explorer Shell 支持的 Overlay Icon 最多 15 个，Windows 自身使用了 4 个，只剩 11 个可扩展使用，如果你开启微软 OneDrive，可能这 11 个位置都被占用，Windows 内部就是按图标名称的字母顺序来优先显示的，导致 Tortoise 图标无法显示。</p><ul><li><p>svn 版本库图标不见修复方法</p><p>只在名字前面加空格, 三个六个空格随意,只要比其它的文件夹名更深就能排前面，然后进程里面重启 explorer 程序就可以了</p></li><li><p>进入注册表路径 <code>\\HKEY_LOCAL_MACHINE\\SOFTWARE\\Microsoft\\Windows\\CurrentVersion\\Explorer\\ShellIconOverlayIdentifiers </code></p></li><li><p>命令方式进入 <code>win+R </code> -&gt; <code>regedit </code> 进入注册表，修改名称排序</p></li><li><p>推荐方式 文件夹右键菜单 -&gt; <code>TortoiseSVN</code> -&gt; <code>settings</code> -&gt; <code>Icon Overlays</code> -&gt; <code>Overlay Handlers</code> -&gt; <code>start registry editor</code></p></li></ul>',70)];r.render=function(s,a,r,i,p,t){return e(),n("div",null,l)};export{a as __pageData,r as default};
